   339		if len(channels) == 0 || (len(channels) == 1 && channels[0] == "") {
   340			pc.common.log.Info().Str("topic", record.Topic).Int32("partition", record.Partition).Msg("no channels found, skip message")
   341			return nil
   342		}
   343		version, err := getUint64HeaderValue(record, pc.config.PublicationDataMode.VersionHeader)
   344		if err != nil {
   345			pc.common.log.Error().Err(err).Str("topic", record.Topic).Int32("partition", record.Partition).Msg("error parsing version header value, skip message")
   346			return nil
   347		}
   348		return pc.dispatcher.DispatchPublication(
   349			ctx,
   350			channels,
   351			api.ConsumedPublication{
   352				Data:           data,
   353				IdempotencyKey: idempotencyKey,
   354				Delta:          delta,
   355				Tags:           publicationTagsFromKafkaRecord(record, pc.config.PublicationDataMode.TagsHeaderPrefix),
   356				Version:        version,
   357				VersionEpoch:   getHeaderValue(record, pc.config.PublicationDataMode.VersionEpochHeader),
   358			},
   359		)
   360	}
   361	
   362	func (pc *partitionConsumer) processRecord(ctx context.Context, record *kgo.Record) error {
   363		if pc.config.PublicationDataMode.Enabled {
   364			return pc.processPublicationDataRecord(ctx, record)
   365		}
   366		method := getHeaderValue(record, pc.config.MethodHeader)
   367		return pc.dispatcher.DispatchCommand(ctx, method, record.Value)
   368	}
   369	
   370	func (pc *partitionConsumer) processRecords(records []*kgo.Record) {
   371		for _, record := range records {
   372			select {
   373			case <-pc.partitionCtx.Done():
   374				return
   375			default:
   376			}
   377	
   378			var backoffDuration time.Duration = 0
   379			retries := 0
   380			for {
   381				err := pc.processRecord(pc.partitionCtx, record)
   382				if err == nil {
   383					if retries > 0 {
   384						pc.common.log.Info().Str("topic", record.Topic).Int32("partition", record.Partition).Msg("OK processing message after errors")
   385					}
   386					if logging.Enabled(logging.TraceLevel) {
   387						pc.common.log.Trace().Str("topic", record.Topic).Int32("partition", record.Partition).Int64("offset", record.Offset).Msg("record processed")
   388					}
   389					metrics.ConsumerProcessedTotal.WithLabelValues(pc.name).Inc()
   390					pc.cl.MarkCommitRecords(record)
   391					break
   392				}
   393				if errors.Is(err, context.Canceled) {
   394					return
   395				}
   396				retries++
   397				backoffDuration = getNextBackoffDuration(backoffDuration, retries)
   398				metrics.ConsumerErrorsTotal.WithLabelValues(pc.name).Inc()
   399				pc.common.log.Error().Err(err).Str("topic", record.Topic).Int32("partition", record.Partition).Str("next_attempt_in", backoffDuration.String()).Msg("error processing consumed record")
   400				select {
   401				case <-time.After(backoffDuration):
   402				case <-pc.partitionCtx.Done():
   403					return
   404				}
   405			}
   406		}
   407	}
   408	
   409	func (pc *partitionConsumer) consume() {
   410		if logging.Enabled(logging.DebugLevel) {
   411			pc.common.log.Debug().Str("topic", pc.topic).Int32("partition", pc.partition).Msg("starting partition consumer")
   412		}
   413		defer close(pc.done)
   414		defer pc.queue.Close()
   415		defer func() {
   416			if logging.Enabled(logging.DebugLevel) {
   417				// Queue is closed, partition consumer is shutting down.
   418				pc.common.log.Debug().Str("topic", pc.topic).Int32("partition", pc.partition).Msg("partition consumer shutting down")
   419			}
   420		}()
   421	
   422		partitionsToResume := map[string][]int32{pc.topic: {pc.partition}}
   423		resumeConsuming := func() {
   424			pc.cl.ResumeFetchPartitions(partitionsToResume)
   425		}
   426		defer resumeConsuming()
   427	
   428		for {
   429			select {
   430			case <-pc.partitionCtx.Done():
   431				return
   432			case <-pc.queue.NotEmpty():
   433				if pc.queue.IsClosed() {
   434					return
   435				}
   436				// Process all available items in the queue.
   437				for {
   438					select {
   439					case <-pc.partitionCtx.Done():
   440						return
   441					default:
   442					}
   443					p, ok := pc.queue.Pop()
   444					if !ok {
   445						break
   446					}
   447					pc.processRecords(p.Records)
   448					// Resume partition after processing this batch. Only one additional batch will
   449					// be added to the queue before we pause again.
   450					resumeConsuming()
   451				}
   452			}
   453		}
   454	}
   455	
   456	// unboundedQueue implements an unbounded queue for FetchTopicPartition
   457	type unboundedQueue struct {
   458		mu         sync.RWMutex
   459		items      []kgo.FetchTopicPartition
   460		numRecords int
   461		notEmpty   chan struct{}
   462		closed     bool
   463	}
   464	
   465	func newUnboundedQueue() *unboundedQueue {
   466		return &unboundedQueue{
   467			items:    make([]kgo.FetchTopicPartition, 0),
   468			notEmpty: make(chan struct{}, 1),
   469		}
   470	}
   471	
   472	func (q *unboundedQueue) Push(item kgo.FetchTopicPartition) bool {
   473		q.mu.Lock()
   474		defer q.mu.Unlock()
   475	
   476		if q.closed {
   477			return false
   478		}
   479	
   480		q.items = append(q.items, item)
   481		q.numRecords += len(item.Records)
   482	
   483		// Signal that queue is not empty.
   484		select {
   485		case q.notEmpty <- struct{}{}:
   486		default:
   487		}
   488	
   489		return true
   490	}
   491	
   492	func (q *unboundedQueue) Pop() (kgo.FetchTopicPartition, bool) {
   493		q.mu.Lock()
   494		defer q.mu.Unlock()
   495	
   496		if q.closed || len(q.items) == 0 {
   497			return kgo.FetchTopicPartition{}, false
   498		}
   499	
   500		// We do not expect many items in the queue, so we can use a simple slice pop operation and
   501		// not worry about memory being reserved for the underlying slice.
   502		item := q.items[0]
   503		q.items[0] = kgo.FetchTopicPartition{} // Clear the first item for faster GC.
   504		q.items = q.items[1:]
   505		q.numRecords -= len(item.Records)
   506	
   507		return item, true
   508	}
   509	
   510	func (q *unboundedQueue) NumRecords() int {
   511		q.mu.RLock()
   512		defer q.mu.RUnlock()
   513		return q.numRecords
   514	}
   515	
   516	func (q *unboundedQueue) Close() {
   517		q.mu.Lock()
   518		defer q.mu.Unlock()
   519	
   520		if !q.closed {
   521			q.closed = true
   522			close(q.notEmpty)
   523		}
   524	}
   525	
   526	func (q *unboundedQueue) IsClosed() bool {
   527		q.mu.RLock()
   528		defer q.mu.RUnlock()
   529		return q.closed
   530	}
   531	
   532	func (q *unboundedQueue) NotEmpty() <-chan struct{} {
   533		return q.notEmpty
   534	}
   535

