func (c *KafkaConsumer) awsMSKIAMMechanism() (sasl.Mechanism, error) {
	if c.config.AssumeRoleARN == "" && c.config.CredentialsProfile == "" {
		return franzaws.Auth{
			AccessKey: c.config.SASLUser,
			SecretKey: c.config.SASLPassword,
		}.AsManagedStreamingIAMMechanism(), nil
	}

	loadOpts := []func(*awsconfig.LoadOptions) error{}
	if c.config.CredentialsProfile != "" {
		loadOpts = append(loadOpts, awsconfig.WithSharedConfigProfile(c.config.CredentialsProfile))
	} else if c.config.SASLUser != "" || c.config.SASLPassword != "" {
		loadOpts = append(loadOpts, awsconfig.WithCredentialsProvider(
			awscredentials.NewStaticCredentialsProvider(c.config.SASLUser, c.config.SASLPassword, ""),
		))
	}

	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()
	awsCfg, err := awsconfig.LoadDefaultConfig(ctx, loadOpts...)
	if err != nil {
		return nil, fmt.Errorf("failed to load AWS config: %w", err)
	}
	if awsCfg.Region == "" {
		awsCfg.Region = inferAWSRegionFromKafkaBrokers(c.config.Brokers)
	}

	credentialsProvider := awsCfg.Credentials
	if c.config.AssumeRoleARN != "" {
		stsClient := sts.NewFromConfig(awsCfg)
		credentialsProvider = stscreds.NewAssumeRoleProvider(stsClient, c.config.AssumeRoleARN)
	}
	credentialsCache := awssdk.NewCredentialsCache(credentialsProvider)

	return franzaws.ManagedStreamingIAM(func(ctx context.Context) (franzaws.Auth, error) {
		credentials, err := credentialsCache.Retrieve(ctx)
		if err != nil {
			return franzaws.Auth{}, fmt.Errorf("failed to retrieve AWS credentials: %w", err)
		}
		return franzaws.Auth{
			AccessKey:     credentials.AccessKeyID,
			SecretKey:     credentials.SecretAccessKey,
			SessionToken: credentials.SessionToken,
		}, nil
	}), nil
}

func inferAWSRegionFromKafkaBrokers(brokers []string) string {
	for _, broker := range brokers {
		if region := inferAWSRegionFromKafkaBroker(broker); region != "" {
			return region
		}
	}
	return ""
}

func inferAWSRegionFromKafkaBroker(broker string) string {
	host, _, err := net.SplitHostPort(broker)
	if err != nil {
		host = broker
	}
	host = strings.TrimSuffix(host, ".")
	parts := strings.Split(host, ".")
	for i, part := range parts {
		if (part == "kafka" || part == "kafka-serverless") && i+1 < len(parts) {
			return parts[i+1]
		}
	}
	return ""
}

